        print("Usage: python todo.py add \"content\"")
        return
    todos = load_todos()
    todos.append(sys.argv[2])
    save_todos(todos)

elif command == "list":
    todos = load_todos()
    for i, todo in enumerate(todos, 1):
        print(f"{i}: {todo}")

elif command == "remove":
    if len(sys.argv) < 3:
        print("Usage: python todo.py remove <ID>")
        return
    try:
        index = int(sys.argv[2]) - 1
    except ValueError:
        return
    todos = load_todos()
    if 0 <= index < len(todos):
        todos.pop(index)
        save_todos(todos)

else:
    print("Usage: python todo.py [add|list|remove] [args]")

